 * Relais simple: un ecrivain -> relais -> lecteur
 * Pattern: 2 pipes, le relais lit d'un et ecrit dans l'autre.
 * ================================================= */
void example_relay(void) {
    int p1[2], p2[2];
    pipe(p1); pipe(p2);
    write(p1[1], "data", 4);
    char buf[32];
    ssize_t n = read(p1[0], buf, sizeof(buf)-1);
    buf[n] = '\0';
    write(p2[1], buf, n);
    n = read(p2[0], buf, sizeof(buf)-1);
    buf[n] = '\0';
    printf("Relayed: %s\n", buf);
    close(p1[0]); close(p1[1]); close(p2[0]); close(p2[1]);
}
